1266 /// Transform (sext icmp) to bitwise / integer operations to eliminate the icmp.
1267 Instruction *InstCombinerImpl::transformSExtICmp(ICmpInst *Cmp,
1268                                                  SExtInst &Sext) {
1269   Value *Op0 = Cmp->getOperand(0), *Op1 = Cmp->getOperand(1);
1270   ICmpInst::Predicate Pred = Cmp->getPredicate();
1271 
1272   // Don't bother if Op1 isn't of vector or integer type.
1273   if (!Op1->getType()->isIntOrIntVectorTy())
1274     return nullptr;
1275 
1276   if (Pred == ICmpInst::ICMP_SLT && match(Op1, m_ZeroInt())) {
1277     // sext (x <s 0) --> ashr x, 31 (all ones if negative)
1278     Value *Sh = ConstantInt::get(Op0->getType(),
1279                                  Op0->getType()->getScalarSizeInBits() - 1);
1280     Value *In = Builder.CreateAShr(Op0, Sh, Op0->getName() + ".lobit");
1281     if (In->getType() != Sext.getType())
1282       In = Builder.CreateIntCast(In, Sext.getType(), true /*SExt*/);
1283 
1284     return replaceInstUsesWith(Sext, In);
1285   }
1286 
1287   if (ConstantInt *Op1C = dyn_cast<ConstantInt>(Op1)) {
1288     // If we know that only one bit of the LHS of the icmp can be set and we
1289     // have an equality comparison with zero or a power of 2, we can transform
1290     // the icmp and sext into bitwise/integer operations.
1291     if (Cmp->hasOneUse() &&
1292         Cmp->isEquality() && (Op1C->isZero() || Op1C->getValue().isPowerOf2())){
1293       KnownBits Known = computeKnownBits(Op0, 0, &Sext);
1294 
1295       APInt KnownZeroMask(~Known.Zero);
1296       if (KnownZeroMask.isPowerOf2()) {
1297         Value *In = Cmp->getOperand(0);
1298 
1299         // If the icmp tests for a known zero bit we can constant fold it.
1300         if (!Op1C->isZero() && Op1C->getValue() != KnownZeroMask) {
1301           Value *V = Pred == ICmpInst::ICMP_NE ?
1302                        ConstantInt::getAllOnesValue(Sext.getType()) :
1303                        ConstantInt::getNullValue(Sext.getType());
1304           return replaceInstUsesWith(Sext, V);
1305         }
1306 
1307         if (!Op1C->isZero() == (Pred == ICmpInst::ICMP_NE)) {
1308           // sext ((x & 2^n) == 0)   -> (x >> n) - 1
1309           // sext ((x & 2^n) != 2^n) -> (x >> n) - 1
1310           unsigned ShiftAmt = KnownZeroMask.countr_zero();
1311           // Perform a right shift to place the desired bit in the LSB.
1312           if (ShiftAmt)
1313             In = Builder.CreateLShr(In,
1314                                     ConstantInt::get(In->getType(), ShiftAmt));
1315 
1316           // At this point "In" is either 1 or 0. Subtract 1 to turn
1317           // {1, 0} -> {0, -1}.
1318           In = Builder.CreateAdd(In,
1319                                  ConstantInt::getAllOnesValue(In->getType()),
1320                                  "sext");
1321         } else {
1322           // sext ((x & 2^n) != 0)   -> (x << bitwidth-n) a>> bitwidth-1
1323           // sext ((x & 2^n) == 2^n) -> (x << bitwidth-n) a>> bitwidth-1
1324           unsigned ShiftAmt = KnownZeroMask.countl_zero();
1325           // Perform a left shift to place the desired bit in the MSB.
1326           if (ShiftAmt)
1327             In = Builder.CreateShl(In,
1328                                    ConstantInt::get(In->getType(), ShiftAmt));
1329 
1330           // Distribute the bit over the whole bit width.
1331           In = Builder.CreateAShr(In, ConstantInt::get(In->getType(),
1332                                   KnownZeroMask.getBitWidth() - 1), "sext");
1333         }
1334 
1335         if (Sext.getType() == In->getType())
1336           return replaceInstUsesWith(Sext, In);
1337         return CastInst::CreateIntegerCast(In, Sext.getType(), true/*SExt*/);
1338       }
1339     }
1340   }
1341 
1342   return nullptr;
1343 }
