1345 /// Return true if we can take the specified value and return it as type Ty
1346 /// without inserting any new casts and without changing the value of the common
1347 /// low bits.  This is used by code that tries to promote integer operations to
1348 /// a wider types will allow us to eliminate the extension.
1349 ///
1350 /// This function works on both vectors and scalars.
1351 ///
1352 static bool canEvaluateSExtd(Value *V, Type *Ty) {
1353   assert(V->getType()->getScalarSizeInBits() < Ty->getScalarSizeInBits() &&
1354          "Can't sign extend type to a smaller type");
1355   if (canAlwaysEvaluateInType(V, Ty))
1356     return true;
1357   if (canNotEvaluateInType(V, Ty))
1358     return false;
1359 
1360   auto *I = cast<Instruction>(V);
1361   switch (I->getOpcode()) {
1362   case Instruction::SExt:  // sext(sext(x)) -> sext(x)
1363   case Instruction::ZExt:  // sext(zext(x)) -> zext(x)
1364   case Instruction::Trunc: // sext(trunc(x)) -> trunc(x) or sext(x)
1365     return true;
1366   case Instruction::And:
1367   case Instruction::Or:
1368   case Instruction::Xor:
1369   case Instruction::Add:
1370   case Instruction::Sub:
1371   case Instruction::Mul:
1372     // These operators can all arbitrarily be extended if their inputs can.
1373     return canEvaluateSExtd(I->getOperand(0), Ty) &&
1374            canEvaluateSExtd(I->getOperand(1), Ty);
1375 
1376   //case Instruction::Shl:   TODO
1377   //case Instruction::LShr:  TODO
1378 
1379   case Instruction::Select:
1380     return canEvaluateSExtd(I->getOperand(1), Ty) &&
1381            canEvaluateSExtd(I->getOperand(2), Ty);
1382 
1383   case Instruction::PHI: {
1384     // We can change a phi if we can change all operands.  Note that we never
1385     // get into trouble with cyclic PHIs here because we only consider
1386     // instructions with a single use.
1387     PHINode *PN = cast<PHINode>(I);
1388     for (Value *IncValue : PN->incoming_values())
1389       if (!canEvaluateSExtd(IncValue, Ty)) return false;
1390     return true;
1391   }
1392   default:
1393     // TODO: Can handle more cases here.
1394     break;
1395   }
1396 
1397   return false;
1398 }
