1400 Instruction *InstCombinerImpl::visitSExt(SExtInst &Sext) {
1401   // If this sign extend is only used by a truncate, let the truncate be
1402   // eliminated before we try to optimize this sext.
1403   if (Sext.hasOneUse() && isa<TruncInst>(Sext.user_back()))
1404     return nullptr;
1405 
1406   if (Instruction *I = commonCastTransforms(Sext))
1407     return I;
1408 
1409   Value *Src = Sext.getOperand(0);
1410   Type *SrcTy = Src->getType(), *DestTy = Sext.getType();
1411   unsigned SrcBitSize = SrcTy->getScalarSizeInBits();
1412   unsigned DestBitSize = DestTy->getScalarSizeInBits();
1413 
1414   // If the value being extended is zero or positive, use a zext instead.
1415   if (isKnownNonNegative(Src, SQ.getWithInstruction(&Sext))) {
1416     auto CI = CastInst::Create(Instruction::ZExt, Src, DestTy);
1417     CI->setNonNeg(true);
1418     return CI;
1419   }
1420 
1421   // Try to extend the entire expression tree to the wide destination type.
1422   if (shouldChangeType(SrcTy, DestTy) && canEvaluateSExtd(Src, DestTy)) {
1423     // Okay, we can transform this!  Insert the new expression now.
1424     LLVM_DEBUG(
1425         dbgs() << "ICE: EvaluateInDifferentType converting expression type"
1426                   " to avoid sign extend: "
1427                << Sext << '\n');
1428     Value *Res = EvaluateInDifferentType(Src, DestTy, true);
1429     assert(Res->getType() == DestTy);
1430 
1431     // If the high bits are already filled with sign bit, just replace this
1432     // cast with the result.
1433     if (ComputeNumSignBits(Res, 0, &Sext) > DestBitSize - SrcBitSize)
1434       return replaceInstUsesWith(Sext, Res);
1435 
1436     // We need to emit a shl + ashr to do the sign extend.
1437     Value *ShAmt = ConstantInt::get(DestTy, DestBitSize-SrcBitSize);
1438     return BinaryOperator::CreateAShr(Builder.CreateShl(Res, ShAmt, "sext"),
1439                                       ShAmt);
1440   }
1441 
1442   Value *X;
1443   if (match(Src, m_Trunc(m_Value(X)))) {
1444     // If the input has more sign bits than bits truncated, then convert
1445     // directly to final type.
1446     unsigned XBitSize = X->getType()->getScalarSizeInBits();
1447     if (ComputeNumSignBits(X, 0, &Sext) > XBitSize - SrcBitSize)
1448       return CastInst::CreateIntegerCast(X, DestTy, /* isSigned */ true);
1449 
1450     // If input is a trunc from the destination type, then convert into shifts.
1451     if (Src->hasOneUse() && X->getType() == DestTy) {
1452       // sext (trunc X) --> ashr (shl X, C), C
1453       Constant *ShAmt = ConstantInt::get(DestTy, DestBitSize - SrcBitSize);
1454       return BinaryOperator::CreateAShr(Builder.CreateShl(X, ShAmt), ShAmt);
1455     }
1456 
1457     // If we are replacing shifted-in high zero bits with sign bits, convert
1458     // the logic shift to arithmetic shift and eliminate the cast to
1459     // intermediate type:
1460     // sext (trunc (lshr Y, C)) --> sext/trunc (ashr Y, C)
1461     Value *Y;
1462     if (Src->hasOneUse() &&
1463         match(X, m_LShr(m_Value(Y),
1464                         m_SpecificIntAllowUndef(XBitSize - SrcBitSize)))) {
1465       Value *Ashr = Builder.CreateAShr(Y, XBitSize - SrcBitSize);
1466       return CastInst::CreateIntegerCast(Ashr, DestTy, /* isSigned */ true);
1467     }
1468   }
1469 
1470   if (auto *Cmp = dyn_cast<ICmpInst>(Src))
1471     return transformSExtICmp(Cmp, Sext);
1472 
1473   // If the input is a shl/ashr pair of a same constant, then this is a sign
1474   // extension from a smaller value.  If we could trust arbitrary bitwidth
1475   // integers, we could turn this into a truncate to the smaller bit and then
1476   // use a sext for the whole extension.  Since we don't, look deeper and check
1477   // for a truncate.  If the source and dest are the same type, eliminate the
1478   // trunc and extend and just do shifts.  For example, turn:
1479   //   %a = trunc i32 %i to i8
1480   //   %b = shl i8 %a, C
1481   //   %c = ashr i8 %b, C
